module top_module(d,clk,resetn,en,q);input clk;
input resetn;
input en;
input [31:0] d;
output [31:0] q;
reg [31:0] q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk  or posedge dbg_halt)		
begin
	if (resetn==0)
		q<=0;
	else if (en==1)
		q<=d;
end

endmodule
